"use client"

import { useState, useEffect, useMemo, useRef } from "react";
import dynamic from "next/dynamic";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Search, Navigation, Loader2, MapPin, Zap, ShieldAlert, Timer, Flag, X, Play, StopCircle, Target } from "lucide-react";
import { useUser, useFirestore, useCollection, useMemoFirebase } from "@/firebase";
import { collection, query, orderBy } from "firebase/firestore";
import { useDriving, RoadFeature } from "@/context/driving-context";
import { calculateRoute } from "@/services/navigation/routeService";
import { searchLocations, SearchResult } from "@/services/navigation/geocodingService";
import { fetchRoadMetadata } from "@/services/navigation/osmService";
import { useToast } from "@/hooks/use-toast";
import { cn } from "@/lib/utils";

const DriveRankMap = dynamic(() => import("@/components/map/DriveRankMap"), { 
  ssr: false,
  loading: () => <div className="w-full h-full bg-zinc-950 flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-accent" /></div>
});

export default function NavigationPage() {
  const { 
    currentCoords, heading, speed,
    destination, routeData, isNavigating, roadFeatures,
    setDestination, setRouteData, setIsNavigating, clearNavigation, setRoadFeatures
  } = useDriving();
  
  const db = useFirestore();
  const { toast } = useToast();
  
  const [searchQuery, setSearchQuery] = useState("");
  const [searchResults, setSearchResults] = useState<SearchResult[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [forceCenter, setForceCenter] = useState(0);
  const lastFetchCoords = useRef<{lat: number, lng: number} | null>(null);

  const radarQuery = useMemoFirebase(() => {
    if (!db) return null;
    return query(collection(db, "radar_reports"), orderBy("createdAt", "desc"));
  }, [db]);
  const { data: alerts } = useCollection(radarQuery);

  // Debounced search
  useEffect(() => {
    const timer = setTimeout(async () => {
      if (searchQuery.length >= 2) {
        setIsSearching(true);
        const results = await searchLocations(searchQuery);
        setSearchResults(results);
        setIsSearching(false);
      } else {
        setSearchResults([]);
      }
    }, 400);
    return () => clearTimeout(timer);
  }, [searchQuery]);

  // Fetch OSM Metadata (Road info)
  useEffect(() => {
    if (!currentCoords) return;

    const dist = lastFetchCoords.current 
      ? Math.sqrt(Math.pow(currentCoords.lat - lastFetchCoords.current.lat, 2) + Math.pow(currentCoords.lng - lastFetchCoords.current.lng, 2))
      : 1;

    // Fetch vetëm nëse kemi lëvizur më shumë se ~500m
    if (dist > 0.005) {
      lastFetchCoords.current = currentCoords;
      fetchRoadMetadata(currentCoords.lat, currentCoords.lng, 2000).then(data => {
        const nodes = new Map();
        data.elements.forEach(el => { if (el.type === 'node') nodes.set(el.id, el); });

        const features: RoadFeature[] = data.elements.map(el => {
          if (el.type === 'node' && el.tags) {
            if (el.tags.highway === 'traffic_signals') return { type: 'traffic_light', lat: el.lat, lng: el.lon, id: `node-${el.id}` } as RoadFeature;
            if (el.tags.highway === 'stop') return { type: 'stop_sign', lat: el.lat, lng: el.lon, id: `node-${el.id}` } as RoadFeature;
          }
          if (el.type === 'way' && el.tags) {
            const path = el.nodes.map((nodeId: number) => {
              const node = nodes.get(nodeId);
              return node ? [node.lat, node.lon] as [number, number] : null;
            }).filter(Boolean);

            if (el.tags.maxspeed) return { type: 'speed_limit', path, value: el.tags.maxspeed, id: `way-${el.id}` } as RoadFeature;
            if (el.tags.junction === 'roundabout') return { type: 'roundabout', path, id: `way-${el.id}` } as RoadFeature;
            if (el.tags.oneway === 'yes') return { type: 'oneway', path, id: `way-${el.id}` } as RoadFeature;
          }
          return null;
        }).filter(Boolean) as RoadFeature[];

        setRoadFeatures(features);
      });
    }
  }, [currentCoords, setRoadFeatures]);

  const handleSelectDestination = async (result: SearchResult) => {
    setDestination(result);
    setSearchQuery("");
    setSearchResults([]);
    
    if (!currentCoords) {
      toast({ variant: "destructive", title: "GPS 📍", description: "Lejoni qasjen në lokacion." });
      return;
    }

    const route = await calculateRoute(currentCoords, { lat: result.lat, lng: result.lng });
    if (route) {
      setRouteData(route);
      toast({ title: "RRUGA U GJET 🏁", description: `Distanca: ${(route.distance / 1000).toFixed(1)} km deri te ${result.name}` });
    } else {
      toast({ variant: "destructive", title: "GABIM ❌", description: "Lokacioni nuk u arrit me makinë." });
    }
  };

  const handleStartNav = () => {
    if (!routeData) return;
    setIsNavigating(true);
    toast({ title: "NAVIGIMI FILLOI 🔥", description: "Vozit me kujdes!" });
  };

  const handleStopNav = () => {
    setIsNavigating(false);
    clearNavigation();
  };

  const handleClearSelection = () => {
    clearNavigation();
    setSearchQuery("");
    setSearchResults([]);
  };

  const handleRecenter = () => {
    setForceCenter(prev => prev + 1);
  };

  const alertsOnRoute = useMemo(() => {
    if (!routeData || !alerts) return [];
    return alerts.filter(alert => {
      return routeData.coordinates.some(coord => {
        const dist = Math.sqrt(Math.pow(alert.lat - coord[0], 2) + Math.pow(alert.lng - coord[1], 2));
        return dist < 0.002;
      });
    });
  }, [routeData, alerts]);

  return (
    <div className="flex flex-col h-screen bg-black relative overflow-hidden">
      <div className="absolute inset-0 z-0">
        <DriveRankMap 
          userLocation={currentCoords} 
          heading={heading}
          route={routeData?.coordinates || null} 
          alerts={alerts || []}
          roadFeatures={roadFeatures}
          destination={destination}
          isNavigating={isNavigating}
          forceCenter={forceCenter}
        />
      </div>

      <div className="absolute top-12 left-4 right-4 z-20 space-y-2">
        {!isNavigating ? (
          <div className="relative">
            <Card className="glass-card p-4 rounded-2xl border-white/5 shadow-2xl flex items-center gap-3 bg-zinc-950/90 backdrop-blur-3xl">
              <Search className="w-5 h-5 text-accent shrink-0" />
              <Input 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Kërko lagje, rrugë, biznes..."
                className="bg-transparent border-none h-12 p-0 text-white placeholder:text-zinc-500 focus-visible:ring-0 font-black italic uppercase text-base"
              />
              {isSearching && <Loader2 className="w-4 h-4 animate-spin text-accent" />}
              { (searchQuery || destination) && (
                <button onClick={handleClearSelection} className="text-zinc-500 hover:text-white p-2">
                  <X className="w-6 h-6" />
                </button>
              )}
            </Card>

            {searchResults.length > 0 && (
              <Card className="mt-3 glass-card border-white/10 rounded-2xl shadow-2xl overflow-hidden max-h-[340px] overflow-y-auto no-scrollbar bg-zinc-950/95 backdrop-blur-3xl animate-in slide-in-from-top-2 duration-300">
                {searchResults.map((result, idx) => (
                  <button 
                    key={idx}
                    onClick={() => handleSelectDestination(result)}
                    className="w-full p-4 flex items-center gap-4 hover:bg-white/5 border-b border-white/5 last:border-none text-left transition-all active:scale-[0.98]"
                  >
                    <div className="w-10 h-10 rounded-xl bg-accent/10 flex items-center justify-center shrink-0 border border-accent/20">
                      <MapPin className="w-5 h-5 text-accent" />
                    </div>
                    <div className="flex flex-col min-w-0">
                      <span className="text-xs font-black text-white uppercase italic truncate">{result.name}</span>
                      <span className="text-[8px] font-bold text-zinc-500 uppercase truncate max-w-[240px] mt-0.5">{result.displayName}</span>
                    </div>
                  </button>
                ))}
              </Card>
            )}
          </div>
        ) : (
          <Card className="glass-card p-5 rounded-[2rem] border-red-500/20 shadow-2xl flex items-center justify-between bg-zinc-950/90 backdrop-blur-3xl animate-in slide-in-from-top duration-500 ring-2 ring-red-600/20">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-red-600 rounded-2xl flex items-center justify-center animate-pulse shadow-lg shadow-red-600/20">
                <Navigation className="w-7 h-7 text-white" />
              </div>
              <div className="flex flex-col">
                <span className="text-[9px] font-black text-red-500 uppercase tracking-[0.3em]">NAVIGIMI AKTIV 🇽🇰</span>
                <span className="text-sm font-black text-white uppercase italic truncate max-w-[160px]">{destination?.name}</span>
              </div>
            </div>
            <div className="flex gap-2">
               <div className="bg-black/40 px-3 py-1 rounded-xl border border-white/10 flex flex-col items-center">
                  <span className="text-[14px] font-black text-white leading-none">{speed}</span>
                  <span className="text-[6px] font-bold text-accent">KM/H</span>
               </div>
               <Button onClick={handleStopNav} variant="destructive" className="rounded-2xl h-12 px-4 font-black uppercase text-[10px] shadow-xl border-b-4 border-red-900">
                STOP
              </Button>
            </div>
          </Card>
        )}
      </div>

      <div className="absolute bottom-32 right-4 z-20 flex flex-col gap-4">
        <Button 
          onClick={handleRecenter}
          className="w-14 h-14 rounded-2xl bg-zinc-950/90 border border-white/10 text-white shadow-2xl flex items-center justify-center active:scale-90 transition-transform hover:bg-zinc-900"
        >
          <Target className="w-7 h-7 text-accent" />
        </Button>
      </div>

      {routeData && !isNavigating && (
        <div className="absolute bottom-24 left-4 right-4 z-20 space-y-4 animate-in slide-in-from-bottom-6 duration-500">
          {alertsOnRoute.length > 0 && (
            <Badge className="w-full bg-red-600/90 backdrop-blur-xl text-white font-black uppercase italic py-3 rounded-2xl border border-red-500/50 shadow-2xl animate-pulse flex items-center justify-center gap-3">
              <ShieldAlert className="w-5 h-5" />
              {alertsOnRoute.length} ALERTE PËRPARA! 📡
            </Badge>
          )}

          <Card className="glass-card p-6 rounded-[2.5rem] border-accent/20 shadow-2xl sporty-gradient bg-zinc-950/90">
            <div className="grid grid-cols-3 gap-3 mb-6">
              <div className="flex flex-col items-center bg-white/5 p-3 rounded-2xl">
                <Timer className="w-5 h-5 text-muted-foreground mb-1.5" />
                <span className="text-[7px] font-black uppercase text-muted-foreground tracking-widest">MËRRIJA</span>
                <span className="text-sm font-black text-white italic">{Math.round(routeData.duration / 60)} MIN</span>
              </div>
              <div className="flex flex-col items-center bg-white/5 p-3 rounded-2xl border border-accent/20">
                <Flag className="w-5 h-5 text-accent mb-1.5" />
                <span className="text-[7px] font-black uppercase text-muted-foreground tracking-widest">DISTANCA</span>
                <span className="text-sm font-black text-accent italic">{(routeData.distance / 1000).toFixed(1)} KM</span>
              </div>
              <div className="flex flex-col items-center bg-white/5 p-3 rounded-2xl">
                <Zap className="w-5 h-5 text-red-500 mb-1.5" />
                <span className="text-[7px] font-black uppercase text-muted-foreground tracking-widest">PENGESA</span>
                <span className="text-sm font-black text-red-500 italic">{roadFeatures.filter(f => f.type !== 'speed_limit').length}</span>
              </div>
            </div>
            <div className="flex gap-3">
              <Button 
                onClick={handleClearSelection}
                variant="outline"
                className="flex-1 h-14 rounded-2xl font-black text-[11px] uppercase border-white/10 text-zinc-500"
              >
                ANULO
              </Button>
              <Button 
                onClick={handleStartNav}
                className="flex-[2] h-14 bg-accent hover:bg-accent/90 text-background font-black text-lg uppercase italic rounded-2xl shadow-xl border-b-4 border-accent-foreground/30"
              >
                NISU TANI <Play className="w-5 h-5 ml-2 fill-current" />
              </Button>
            </div>
          </Card>
        </div>
      )}

      <BottomNav />
    </div>
  );
}
