/**
 * @fileOverview Shërbimi për kërkimin e adresave në Kosovë duke përdorur Nominatim API.
 * Optimizuar për lagje, rrugë, biznese dhe pika interesi me kërkim fleksibël (fuzzy).
 */

export interface SearchResult {
  name: string;
  lat: number;
  lng: number;
  displayName: string;
}

/**
 * Normalizon tekstin për kërkim më të lehtë (heq ç, ë, etj)
 */
function normalizeQuery(query: string): string {
  return query
    .toLowerCase()
    .replace(/ç/g, 'c')
    .replace(/ë/g, 'e')
    .replace(/q/g, 'q') // Sigurohemi që q mbetet q
    .trim();
}

export async function searchLocations(query: string): Promise<SearchResult[]> {
  if (!query || query.length < 2) return [];

  try {
    const normalized = normalizeQuery(query);
    
    // Kërkojmë me tekstin origjinal dhe atë të normalizuar për rezultate maksimale
    // Nominatim preferon formatin "emri, qyteti" ose thjesht "emri" brenda viewbox
    let searchQuery = query;
    if (!query.toLowerCase().includes('kosov')) {
      searchQuery = `${query}`;
    }

    // Parametrat e optimizuar për Kosovë
    const params = new URLSearchParams({
      q: searchQuery,
      countrycodes: 'xk',
      format: 'json',
      addressdetails: '1',
      namedetails: '1',
      limit: '10',
      dedupe: '1',
      // Viewbox përfshin të gjithë Kosovën për kërkim më të shpejtë lokal
      viewbox: '20.0,41.8,21.8,43.3',
      bounded: '0' // E bëjmë 0 që të gjejë rezultate edhe nëse janë pak jashtë koordinatave strikte
    });

    const url = `https://nominatim.openstreetmap.org/search?${params.toString()}`;
    
    const response = await fetch(url, {
      headers: {
        'Accept-Language': 'sq, en',
        'User-Agent': 'DriveRankKosova/2.1'
      }
    });
    
    const data = await response.json();

    if (!data || data.length === 0 && normalized !== query.toLowerCase()) {
      // Nëse nuk gjen asgjë, provo me tekstin e normalizuar (pa ç, ë)
      return searchLocations(normalized);
    }

    return data.map((item: any) => {
      const address = item.address;
      
      // Prioritizojmë emrin më të shkurtër dhe më të njohur
      const name = item.namedetails?.name || 
                   item.namedetails?.['name:sq'] || 
                   item.name || 
                   address.road || 
                   address.amenity || 
                   address.shop || 
                   address.suburb || 
                   item.display_name.split(',')[0];
      
      return {
        name: name,
        lat: parseFloat(item.lat),
        lng: parseFloat(item.lon),
        displayName: item.display_name
      };
    });
  } catch (error) {
    console.error("Gjeokodimi dështoi:", error);
    return [];
  }
}
